#nullable enable // autogenerated

using System;
using MongoDB.Bson.Serialization.Attributes;

namespace MVZ2.Options
{
    public class HPBarOptions
    {
        public SerializableHPBarOptions ToSerializable()
        {
            return new SerializableHPBarOptions()
            {
                enabled = enabled,
                autoHide = autoHide,
                hoverDisplayRange = hoverDisplayRange,
                amountMode = amountMode
            };
        }
        public void LoadFromSerializable(SerializableHPBarOptions options)
        {
            if (options == null)
                return;
            enabled = options.enabled;
            autoHide = options.autoHide;
            hoverDisplayRange = options.hoverDisplayRange;
            amountMode = options.amountMode;
        }
        public bool enabled;
        public bool autoHide;
        public float hoverDisplayRange;
        public int amountMode;
    }
    [Serializable]
    [BsonIgnoreExtraElements]
    public class SerializableHPBarOptions
    {
        public bool enabled;
        public bool autoHide;
        public float hoverDisplayRange;
        public int amountMode;
    }
    public static class HPBarAmountMode
    {
        public const int HIDDEN = 0;
        public const int CURRENT_ONLY = 1;
        public const int CURRENT_AND_MAX = 2;

        public const int COUNT = 3;
    }
}
